import { clipboard } from "electron";
import { findAppProfile, type InsertionMode } from "../shared/settings";
import { type SettingsStore } from "./settings-store";
import { WindowsHelperService } from "./windows-helper-service";

const FOCUS_SETTLE_DELAY_MS = 120;
const CLIPBOARD_RESTORE_DELAY_MS = 250;
const REMOTE_CLIPBOARD_RESTORE_DELAY_MS = 1500;

interface InsertOptions {
  mode?: InsertionMode;
  hwnd?: string | null;
  processName?: string | null;
}

interface ClipboardSnapshot {
  formats: string[];
  data: Electron.Data;
  buffers: {
    format: string;
    buffer: Buffer;
  }[];
}

export class InsertionService {
  constructor(
    private readonly windowsHelperService: WindowsHelperService,
    private readonly settingsStore: SettingsStore
  ) {}

  async copyForInsertion(text: string): Promise<void> {
    clipboard.writeText(text);
  }

  async insertIntoActiveApp(text: string, options?: InsertOptions): Promise<void> {
    await this.insertText(text, options);
  }

  async insertIntoWindow(
    text: string,
    hwnd: string,
    options?: InsertOptions
  ): Promise<void> {
    await this.windowsHelperService.focusWindow(hwnd);
    await wait(FOCUS_SETTLE_DELAY_MS);
    await this.insertText(text, { ...options, hwnd });
  }

  async pasteIntoActiveApp(text: string): Promise<void> {
    await this.insertIntoActiveApp(text);
  }

  async pasteIntoWindow(text: string, hwnd: string): Promise<void> {
    await this.insertIntoWindow(text, hwnd);
  }

  private async insertText(text: string, options?: InsertOptions): Promise<void> {
    const settings = await this.settingsStore.get();
    const profile = findAppProfile(settings.appProfiles, options?.processName ?? null);
    const mode = options?.mode ?? profile?.insertionMode ?? settings.insertionMode;

    if (mode === "clipboard") {
      await this.pasteWithClipboardRestore(text, settings.restoreClipboard, {
        pasteDelayMs: 0,
        restoreDelayMs: CLIPBOARD_RESTORE_DELAY_MS
      });
      return;
    }

    if (mode === "remoteClipboard") {
      await this.pasteWithClipboardRestore(text, settings.restoreClipboard, {
        pasteDelayMs: settings.remoteClipboardPasteDelayMs,
        restoreDelayMs: REMOTE_CLIPBOARD_RESTORE_DELAY_MS
      });
      return;
    }

    if (mode === "keyboard") {
      await this.windowsHelperService.typeText(text, 0);
      return;
    }

    if (mode === "windowsMessaging") {
      await this.windowsHelperService.messageText(
        text,
        usesRemoteControlMessages(options?.processName) ? "character-messages" : "focused-control",
        options?.hwnd
      );
      return;
    }

    for (const chunk of chunkText(text, settings.remoteTypingChunkSize)) {
      await this.windowsHelperService.typeText(chunk, 0);
      await wait(settings.remoteTypingDelayMs);
    }
  }

  private async pasteWithClipboardRestore(
    text: string,
    restoreClipboard: boolean,
    options: {
      pasteDelayMs: number;
      restoreDelayMs: number;
    }
  ): Promise<void> {
    const snapshot = restoreClipboard ? captureClipboard() : null;
    let pasteError: unknown = null;

    try {
      clipboard.writeText(text);
      await this.windowsHelperService.pasteText(options.pasteDelayMs);
    } catch (error) {
      pasteError = error;
    } finally {
      if (snapshot) {
        await wait(options.restoreDelayMs);
        restoreClipboardSnapshot(snapshot);
      }
    }

    if (pasteError) {
      throw pasteError;
    }
  }
}

function captureClipboard(): ClipboardSnapshot {
  const formats = clipboard.availableFormats("clipboard");
  const data: Electron.Data = {};

  if (hasFormat(formats, "text/plain")) {
    data.text = clipboard.readText("clipboard");
  }

  if (hasFormat(formats, "text/html")) {
    data.html = clipboard.readHTML("clipboard");
  }

  if (hasFormat(formats, "text/rtf")) {
    data.rtf = clipboard.readRTF("clipboard");
  }

  const image = clipboard.readImage("clipboard");
  if (!image.isEmpty()) {
    data.image = image;
  }

  return {
    formats,
    data,
    buffers: formats.flatMap((format) => {
      try {
        const buffer = clipboard.readBuffer(format);
        return buffer.length > 0 ? [{ format, buffer }] : [];
      } catch {
        return [];
      }
    })
  };
}

function restoreClipboardSnapshot(snapshot: ClipboardSnapshot): void {
  clipboard.clear("clipboard");

  if (snapshot.formats.length === 0) {
    return;
  }

  if (hasClipboardData(snapshot.data)) {
    clipboard.write(snapshot.data, "clipboard");
    return;
  }

  for (const entry of snapshot.buffers) {
    try {
      clipboard.writeBuffer(entry.format, entry.buffer, "clipboard");
    } catch {
      // Some Windows clipboard formats cannot be restored through Electron.
    }
  }
}

function hasClipboardData(data: Electron.Data): boolean {
  return Boolean(data.text || data.html || data.rtf || data.image);
}

function hasFormat(formats: string[], format: string): boolean {
  return formats.some((candidate) => candidate.toLowerCase() === format);
}

function usesRemoteControlMessages(processName?: string | null): boolean {
  const normalized = processName?.trim().toLowerCase();
  return (
    normalized === "teamviewer.exe" ||
    normalized === "anydesk.exe" ||
    normalized === "mstsc.exe"
  );
}

function wait(milliseconds: number): Promise<void> {
  return new Promise((resolve) => {
    setTimeout(resolve, milliseconds);
  });
}

function chunkText(text: string, chunkSize: number): string[] {
  const chunks: string[] = [];
  const characters = Array.from(text);

  for (let index = 0; index < characters.length; index += chunkSize) {
    chunks.push(characters.slice(index, index + chunkSize).join(""));
  }

  return chunks;
}

import { mkdir, rename, rm, stat } from "node:fs/promises";
import { createWriteStream } from "node:fs";
import { dirname, join } from "node:path";
import { Readable } from "node:stream";
import { pipeline } from "node:stream/promises";
import { getModelById, type LocalModel, whisperModelCatalog } from "../shared/models";
import { SettingsStore } from "./settings-store";

export class ModelService {
  constructor(private readonly settingsStore: SettingsStore) {}

  async list(): Promise<LocalModel[]> {
    const settings = await this.settingsStore.get();

    return Promise.all(
      whisperModelCatalog.map(async (model) => {
        const localPath = join(settings.modelDirectory, model.fileName);
        const downloadedBytes = await getFileSize(localPath);

        return {
          ...model,
          localPath,
          downloadedBytes,
          status: downloadedBytes > 0 ? "downloaded" : "not-downloaded"
        };
      })
    );
  }

  async download(modelId: string): Promise<LocalModel[]> {
    const model = getModelById(modelId);

    if (!model) {
      throw new Error(`Unknown model: ${modelId}`);
    }

    const settings = await this.settingsStore.get();
    const destination = join(settings.modelDirectory, model.fileName);
    const temporaryDestination = `${destination}.download`;

    await mkdir(dirname(destination), { recursive: true });

    const response = await fetch(model.url);

    if (!response.ok || !response.body) {
      throw new Error(`Failed to download ${model.name}: ${response.status} ${response.statusText}`);
    }

    await pipeline(
      Readable.fromWeb(response.body as unknown as Parameters<typeof Readable.fromWeb>[0]),
      createWriteStream(temporaryDestination)
    );
    await rm(destination, { force: true });
    await rename(temporaryDestination, destination);
    await this.settingsStore.update({ activeModelId: model.id });

    return this.list();
  }

  async delete(modelId: string): Promise<LocalModel[]> {
    const model = getModelById(modelId);

    if (!model) {
      throw new Error(`Unknown model: ${modelId}`);
    }

    const settings = await this.settingsStore.get();
    const destination = join(settings.modelDirectory, model.fileName);

    await rm(destination, { force: true });
    await rm(`${destination}.download`, { force: true });

    if (settings.activeModelId === model.id) {
      const remainingModels = await this.list();
      const nextActiveModel =
        remainingModels.find((item) => item.id !== model.id && item.status === "downloaded")?.id ??
        "small";
      await this.settingsStore.update({ activeModelId: nextActiveModel });
    }

    return this.list();
  }
}

async function getFileSize(path: string): Promise<number> {
  try {
    return (await stat(path)).size;
  } catch {
    return 0;
  }
}

import {
  type StreamingAsrProvider,
  type StreamingAsrRequest,
  type TranscriptTurn
} from "../shared/asr";
import { classifyOpenAiError, formatOpenAiFriendlyError } from "../shared/openai-errors";
import { OPENAI_REALTIME_WHISPER_MODEL_ID } from "../shared/openai-models";
import { getProviderLanguageHint } from "../shared/provider-language";
import { getOpenAiRealtimeTranscriptionDelay } from "../shared/realtime-latency";
import { TranscriptTurnAccumulator } from "../shared/transcript-turns";
import { OpenAiCredentialStore } from "./openai-credential-store";

const OPENAI_REALTIME_URL = "wss://api.openai.com/v1/realtime?intent=transcription";
const OPENAI_REALTIME_MAX_APPEND_BYTES = 15 * 1024 * 1024;
const OPENAI_REALTIME_MIN_COMMIT_BYTES = Math.ceil(24000 * 2 * 0.1);

interface NodeWebSocketInit {
  headers: Record<string, string>;
}

type NodeWebSocketConstructor = new (url: string, init: NodeWebSocketInit) => WebSocket;

export type RealtimePreviewCallback = (turns: TranscriptTurn[]) => void;
export type RealtimeErrorCallback = (error: Error) => void;

export class OpenAiRealtimeAsrProvider implements StreamingAsrProvider {
  readonly providerId = "openai" as const;
  private socket: WebSocket | null = null;
  private readonly turns = new TranscriptTurnAccumulator();
  private finalTranscriptWaiters: {
    resolve: () => void;
    reject: (error: Error) => void;
  }[] = [];
  private sessionReadyWaiters: {
    resolve: () => void;
    reject: (error: Error) => void;
  }[] = [];
  private lastError: Error | null = null;
  private sessionCreatedSeen = false;
  private appendedAudioBytes = 0;

  constructor(
    private readonly credentials: OpenAiCredentialStore,
    private readonly onPreview?: RealtimePreviewCallback,
    private readonly onError?: RealtimeErrorCallback
  ) {}

  async startStreaming(request: StreamingAsrRequest): Promise<void> {
    const apiKey = (await this.credentials.getApiKey())?.trim() ?? null;

    if (!apiKey) {
      throw new Error("OpenAI API key is required before Realtime Cloud Dictation can start.");
    }

    if (request.mode.modelId !== OPENAI_REALTIME_WHISPER_MODEL_ID) {
      throw new Error(`Unsupported realtime OpenAI model: ${request.mode.modelId}.`);
    }

    if (request.audioConfig.sampleRateHz !== 24000 || request.audioConfig.encoding !== "pcm16") {
      throw new Error("OpenAI realtime requires 24 kHz PCM16 mono audio.");
    }

    await this.openSession(
      apiKey,
      request.language,
      request.latencyPreset
    );
  }

  appendPcm16Audio(pcm16Audio: Uint8Array): void {
    this.throwIfRealtimeFailed();

    if (this.socket?.readyState !== WebSocket.OPEN) {
      throw new Error("OpenAI realtime session is not connected.");
    }

    if (pcm16Audio.byteLength === 0 || pcm16Audio.byteLength % 2 !== 0) {
      throw new Error("OpenAI realtime PCM16 audio chunks must be non-empty whole 16-bit samples.");
    }

    if (pcm16Audio.byteLength > OPENAI_REALTIME_MAX_APPEND_BYTES) {
      throw new Error("OpenAI realtime PCM16 audio chunks must be 15 MB or smaller.");
    }

    this.socket.send(JSON.stringify({
      type: "input_audio_buffer.append",
      audio: encodeBase64(pcm16Audio)
    }));
    this.appendedAudioBytes += pcm16Audio.byteLength;
  }

  async commitAudioAndWaitForFinalTranscript(timeoutMs = 10000): Promise<void> {
    this.throwIfRealtimeFailed();

    if (this.socket?.readyState !== WebSocket.OPEN) {
      return;
    }

    if (this.appendedAudioBytes < OPENAI_REALTIME_MIN_COMMIT_BYTES) {
      throw new Error(`Realtime Cloud Dictation did not receive enough microphone audio to finalize. Try holding the hotkey a little longer and check the selected input device. Provider appended ${this.appendedAudioBytes} PCM bytes.`);
    }

    const initialFinalTurnCount = this.finalTurnCount();
    this.socket.send(JSON.stringify({ type: "input_audio_buffer.commit" }));

    if (this.finalTurnCount() > initialFinalTurnCount) {
      return;
    }

    await new Promise<void>((resolve, reject) => {
      const settle = (waiter: {
        resolve: () => void;
        reject: (error: Error) => void;
      }): void => {
        clearTimeout(timeout);
        this.removeFinalTranscriptWaiter(waiter);
      };
      const timeout = setTimeout(() => {
        settle(waiter);
        resolve();
      }, timeoutMs);
      const waiter = {
        resolve: () => {
          settle(waiter);
          resolve();
        },
        reject: (error: Error) => {
          settle(waiter);
          reject(error);
        }
      };
      this.finalTranscriptWaiters.push(waiter);
    });

    this.throwIfRealtimeFailed();

    if (this.finalTurnCount() === initialFinalTurnCount) {
      this.markProvisionalTurnsAsFallback();
    }
  }

  getAppendedAudioBytes(): number {
    return this.appendedAudioBytes;
  }

  stop(reason = "OpenAI realtime session stopped.", options: { preserveLastError?: boolean } = {}): void {
    if (this.sessionReadyWaiters.length > 0 || this.finalTranscriptWaiters.length > 0) {
      this.failRealtime(new Error(reason));
    }

    this.socket?.close();
    this.socket = null;

    if (!options.preserveLastError) {
      this.lastError = null;
    }
  }

  private async openSession(
    apiKey: string,
    language: StreamingAsrRequest["language"],
    latencyPreset: StreamingAsrRequest["latencyPreset"]
  ): Promise<void> {
    this.lastError = null;
    this.sessionCreatedSeen = false;

    await new Promise<void>((resolve, reject) => {
      const NodeWebSocket = WebSocket as unknown as NodeWebSocketConstructor;
      const socket = new NodeWebSocket(OPENAI_REALTIME_URL, {
        headers: {
          Authorization: buildOpenAiRealtimeAuthorizationHeader(apiKey)
        }
      });
      const timeout = setTimeout(() => {
        socket.close();
        const error = this.socket === socket
          ? new Error(this.sessionCreatedSeen
            ? "OpenAI realtime session.update was not acknowledged before the pre-connection buffer expired."
            : "OpenAI realtime session configuration did not complete before the pre-connection buffer expired.")
          : new Error("OpenAI realtime session did not connect before the pre-connection buffer expired.");

        if (this.socket === socket) {
          this.failRealtime(error);
        } else {
          clearTimeout(timeout);
          reject(error);
        }
      }, 5000);

      socket.addEventListener("open", () => {
        this.socket = socket;
        const waiter = {
          resolve: () => {
            clearTimeout(timeout);
            this.removeSessionReadyWaiter(waiter);
            resolve();
          },
          reject: (error: Error) => {
            clearTimeout(timeout);
            this.removeSessionReadyWaiter(waiter);
            reject(error);
          }
        };
        this.sessionReadyWaiters.push(waiter);
        socket.send(JSON.stringify(buildSessionUpdate(
          language,
          latencyPreset
        )));
      }, { once: true });

      socket.addEventListener("message", (event) => { this.handleMessage(event); });
      socket.addEventListener("close", () => {
        if (this.sessionReadyWaiters.length > 0) {
          this.failRealtime(new Error("OpenAI realtime session closed before session configuration completed."));
          return;
        }

        if (this.finalTranscriptWaiters.length > 0) {
          this.failRealtime(new Error("OpenAI realtime session closed before final transcript completed."));
        }
      });
      socket.addEventListener("error", () => {
        clearTimeout(timeout);
        const error = new Error("OpenAI realtime session failed to connect.");
        if (this.socket === socket) {
          this.failRealtime(error);
        } else {
          reject(error);
        }
      }, { once: true });
    });
  }

  private handleMessage(event: MessageEvent): void {
    if (typeof event.data !== "string") {
      return;
    }

    try {
      const payload = JSON.parse(event.data) as {
        type?: string;
        item_id?: string;
        item?: {
          id?: unknown;
        };
        content_index?: number;
        contentIndex?: number;
        transcript?: string;
        delta?: string;
        text?: string;
        error?: {
          code?: unknown;
          type?: unknown;
          message?: unknown;
        };
      };

      if (payload.type === "error" || isRealtimeTranscriptionFailedEvent(payload.type)) {
        this.failRealtime(new Error(formatRealtimeOpenAiError(payload.error)));
        return;
      }

      if (isRealtimeTranscriptionSessionCreatedEvent(payload.type)) {
        this.sessionCreatedSeen = true;
        return;
      }

      if (isRealtimeTranscriptionSessionUpdatedEvent(payload.type)) {
        this.resolveSessionReadyWaiters();
        return;
      }

      const providerItemId = getRealtimeTranscriptKey(
        payload.item_id ?? (typeof payload.item?.id === "string" ? payload.item.id : undefined),
        payload.content_index ?? payload.contentIndex
      );
      const final = isRealtimeTranscriptionCompletedEvent(payload.type);
      const text = payload.transcript ?? payload.delta ?? payload.text ?? "";

      if (!text) {
        return;
      }

      this.onPreview?.(this.turns.apply({
        providerItemId,
        text,
        final,
        append: isRealtimeTranscriptionDeltaEvent(payload.type)
      }));

      if (final) {
        this.resolveFinalTranscriptWaiters();
      }
    } catch {
      // Ignore malformed provider events; do not log transcripts or raw provider responses.
    }
  }

  private finalTurnCount(): number {
    return this.turns.list().filter((turn) => turn.status === "final" && turn.finalText?.trim()).length;
  }

  private markProvisionalTurnsAsFallback(): void {
    let turns = this.turns.list();

    for (const turn of turns) {
      if (turn.status === "provisional" && turn.provisionalText?.trim()) {
        turns = this.turns.markFallback(turn.providerItemId);
      }
    }

    this.onPreview?.(turns);
  }

  private throwIfRealtimeFailed(): void {
    if (this.lastError) {
      throw this.lastError;
    }
  }

  private failRealtime(error: Error): void {
    this.lastError = error;
    this.onError?.(error);
    const sessionWaiters = this.sessionReadyWaiters;
    this.sessionReadyWaiters = [];
    for (const waiter of sessionWaiters) {
      waiter.reject(error);
    }

    const waiters = this.finalTranscriptWaiters;
    this.finalTranscriptWaiters = [];
    for (const waiter of waiters) {
      waiter.reject(error);
    }
  }

  private resolveSessionReadyWaiters(): void {
    const waiters = this.sessionReadyWaiters;
    this.sessionReadyWaiters = [];
    for (const waiter of waiters) {
      waiter.resolve();
    }
  }

  private removeSessionReadyWaiter(waiter: {
    resolve: () => void;
    reject: (error: Error) => void;
  }): void {
    this.sessionReadyWaiters = this.sessionReadyWaiters.filter((candidate) => candidate !== waiter);
  }

  private removeFinalTranscriptWaiter(waiter: {
    resolve: () => void;
    reject: (error: Error) => void;
  }): void {
    this.finalTranscriptWaiters = this.finalTranscriptWaiters.filter((candidate) => candidate !== waiter);
  }

  private resolveFinalTranscriptWaiters(): void {
    const waiters = this.finalTranscriptWaiters;
    this.finalTranscriptWaiters = [];
    for (const waiter of waiters) {
      waiter.resolve();
    }
  }
}

function isRealtimeTranscriptionDeltaEvent(type: string | undefined): boolean {
  return type === "conversation.item.input_audio_transcription.delta" ||
    type === "transcription_session.input_audio_transcription.delta";
}

function isRealtimeTranscriptionCompletedEvent(type: string | undefined): boolean {
  return type === "conversation.item.input_audio_transcription.completed" ||
    type === "transcription_session.input_audio_transcription.completed" ||
    (type?.includes("input_audio_transcription") === true &&
      (type.includes("completed") || type.endsWith(".done")));
}

function isRealtimeTranscriptionFailedEvent(type: string | undefined): boolean {
  return type === "conversation.item.input_audio_transcription.failed" ||
    type === "transcription_session.input_audio_transcription.failed" ||
    (type?.includes("input_audio_transcription") === true &&
      (type.includes("failed") || type.includes("error")));
}

function isRealtimeTranscriptionSessionCreatedEvent(type: string | undefined): boolean {
  return type === "transcription_session.created" || type === "session.created";
}

function isRealtimeTranscriptionSessionUpdatedEvent(type: string | undefined): boolean {
  return type === "transcription_session.updated" || type === "session.updated";
}

function buildOpenAiRealtimeAuthorizationHeader(apiKey: string): string {
  return `Bearer ${apiKey.trim()}`;
}

function getRealtimeTranscriptKey(itemId: string | undefined, contentIndex: number | undefined): string {
  const safeItemId = itemId?.trim() || "current";
  return typeof contentIndex === "number" && Number.isFinite(contentIndex)
    ? `${safeItemId}:${contentIndex}`
    : safeItemId;
}

function formatRealtimeOpenAiError(error: {
  code?: unknown;
  type?: unknown;
  message?: unknown;
} | undefined): string {
  return formatOpenAiFriendlyError(classifyOpenAiError({
    code: typeof error?.code === "string" ? error.code : null,
    type: typeof error?.type === "string" ? error.type : null,
    message: typeof error?.message === "string" ? error.message : null
  }));
}

function encodeBase64(bytes: Uint8Array): string {
  return Buffer.from(bytes).toString("base64");
}

function buildSessionUpdate(
  language: StreamingAsrRequest["language"],
  latencyPreset: StreamingAsrRequest["latencyPreset"]
): unknown {
  const languageHint = getProviderLanguageHint("openai", language);

  return {
    type: "session.update",
    session: {
      type: "transcription",
      audio: {
        input: {
          format: {
            type: "audio/pcm",
            rate: 24000
          },
          transcription: {
            model: OPENAI_REALTIME_WHISPER_MODEL_ID,
            language: languageHint.parameterValue ?? undefined,
            delay: getOpenAiRealtimeTranscriptionDelay(latencyPreset)
          },
          turn_detection: null
        }
      }
    }
  };
}

import { app } from "electron";
import { execFile } from "node:child_process";
import { createWriteStream } from "node:fs";
import { mkdir, readdir, rename, rm } from "node:fs/promises";
import { dirname, join } from "node:path";
import { Readable } from "node:stream";
import { pipeline } from "node:stream/promises";
import { promisify } from "node:util";
import {
  getRuntimeById,
  type WhisperRuntime,
  type WhisperRuntimeBackend,
  type WhisperRuntimeCatalogItem,
  type WhisperRuntimePreference,
  whisperRuntimeCatalog
} from "../shared/runtimes";
import { HardwareService } from "./hardware-service";

const execFileAsync = promisify(execFile);
const executableCandidates = ["whisper-cli.exe", "main.exe"];

export class RuntimeService {
  private readonly runtimeRootDirectory: string;
  private readonly hardwareService = new HardwareService();

  constructor() {
    this.runtimeRootDirectory = join(
      app.getPath("userData"),
      "runtimes",
      "whisper.cpp"
    );
  }

  async getWhisperRuntime(): Promise<WhisperRuntime> {
    return this.getPreferredRuntime("auto");
  }

  async listWhisperRuntimes(): Promise<WhisperRuntime[]> {
    return Promise.all(whisperRuntimeCatalog.map((runtime) => this.hydrateRuntime(runtime)));
  }

  async getPreferredRuntime(
    preference: WhisperRuntimePreference
  ): Promise<WhisperRuntime> {
    const runtimes = await this.listWhisperRuntimes();
    const selectedRuntime = await this.selectRuntime(runtimes, preference);

    return selectedRuntime;
  }

  async installWhisperRuntime(runtimeId?: string): Promise<WhisperRuntime> {
    if (process.platform !== "win32") {
      throw new Error("Managed whisper.cpp runtime installation is currently Windows-only.");
    }

    const runtime = runtimeId ? getRuntimeById(runtimeId) : await this.getInstallTarget("auto");

    if (!runtime) {
      throw new Error(`Unknown whisper.cpp runtime: ${runtimeId ?? "auto"}.`);
    }

    if (!runtime.managed || !runtime.archiveName || !runtime.url) {
      throw new Error(`${runtime.name} is not available as a managed download yet.`);
    }

    const runtimeDirectory = this.getRuntimeDirectory(runtime);
    const archivePath = join(runtimeDirectory, runtime.archiveName);
    const temporaryArchivePath = `${archivePath}.download`;
    const extractDirectory = join(runtimeDirectory, "extract");

    try {
      await mkdir(dirname(archivePath), { recursive: true });
      await rm(extractDirectory, { recursive: true, force: true });
      await mkdir(extractDirectory, { recursive: true });

      const response = await fetch(runtime.url);

      if (!response.ok || !response.body) {
        throw new Error(
          `Failed to download ${runtime.name}: ${response.status} ${response.statusText}`
        );
      }

      await pipeline(
        Readable.fromWeb(response.body as unknown as Parameters<typeof Readable.fromWeb>[0]),
        createWriteStream(temporaryArchivePath)
      );
      await rm(archivePath, { force: true });
      await rename(temporaryArchivePath, archivePath);
      await this.expandArchive(archivePath, extractDirectory);

      const installedRuntime = await this.hydrateRuntime(runtime);

      if (!installedRuntime.executablePath) {
        throw new Error(`Installed ${runtime.name}, but no whisper-cli.exe was found.`);
      }

      return installedRuntime;
    } catch (error) {
      await rm(extractDirectory, { recursive: true, force: true }).catch(() => undefined);
      throw error;
    } finally {
      await rm(temporaryArchivePath, { force: true }).catch(() => undefined);
      await rm(archivePath, { force: true }).catch(() => undefined);
    }
  }

  async getFirstRunCudaRuntimeTarget(): Promise<WhisperRuntimeCatalogItem | null> {
    const hardware = await this.hardwareService.getAccelerationReport();

    if (hardware.recommendedBackend !== "cuda") {
      return null;
    }

    return this.getCudaRuntimeForDriver(hardware.bestGpu?.driverVersion);
  }

  async getExecutablePath(options: {
    allowInstall: boolean;
    preference: WhisperRuntimePreference;
  }): Promise<string | null> {
    const runtime = await this.getPreferredRuntime(options.preference);

    if (runtime.executablePath) {
      return runtime.executablePath;
    }

    if (!options.allowInstall) {
      return null;
    }

    return (await this.installWhisperRuntime(runtime.id)).executablePath;
  }

  private async getInstallTarget(
    preference: WhisperRuntimePreference
  ): Promise<WhisperRuntimeCatalogItem | null> {
    const runtime = await this.getPreferredRuntime(preference);
    return getRuntimeById(runtime.id) ?? null;
  }

  private getCudaRuntimeForDriver(driverVersion?: string): WhisperRuntimeCatalogItem | null {
    const majorDriverVersion = parseDriverMajorVersion(driverVersion);
    const preferredRuntimeId =
      majorDriverVersion !== null && majorDriverVersion < 551
        ? "whisper.cpp-cuda-11.8-x64"
        : "whisper.cpp-cuda-12.4-x64";

    return getRuntimeById(preferredRuntimeId) ?? null;
  }

  private async selectRuntime(
    runtimes: WhisperRuntime[],
    preference: WhisperRuntimePreference
  ): Promise<WhisperRuntime> {
    if (preference !== "auto") {
      return (
        runtimes.find((runtime) => runtime.backend === preference && runtime.status !== "unavailable") ??
        this.requireRuntime(runtimes, "cpu")
      );
    }

    const hardware = await this.hardwareService.getAccelerationReport();
    const preferredBackends: WhisperRuntimeBackend[] =
      hardware.recommendedBackend === "cuda"
        ? ["cuda", "cpu"]
        : hardware.recommendedBackend === "vulkan"
          ? ["vulkan", "cpu"]
          : ["cpu"];

    for (const backend of preferredBackends) {
      const installedRuntime = runtimes.find(
        (runtime) => runtime.backend === backend && runtime.status === "installed"
      );

      if (installedRuntime) {
        return installedRuntime;
      }
    }

    for (const backend of preferredBackends) {
      const managedRuntime = runtimes.find(
        (runtime) => runtime.backend === backend && runtime.managed
      );

      if (managedRuntime) {
        return managedRuntime;
      }
    }

    return this.requireRuntime(runtimes, "cpu");
  }

  private requireRuntime(
    runtimes: WhisperRuntime[],
    backend: WhisperRuntimeBackend
  ): WhisperRuntime {
    const runtime = runtimes.find((item) => item.backend === backend);

    if (!runtime) {
      throw new Error(`No ${backend} whisper.cpp runtime is configured.`);
    }

    return runtime;
  }

  private async hydrateRuntime(runtime: WhisperRuntimeCatalogItem): Promise<WhisperRuntime> {
    const executablePath = await this.findExecutable(runtime);

    return {
      ...runtime,
      executablePath,
      status: executablePath ? "installed" : runtime.managed ? "not-installed" : "unavailable"
    };
  }

  private async expandArchive(archivePath: string, destination: string): Promise<void> {
    await execFileAsync("powershell.exe", [
      "-NoProfile",
      "-ExecutionPolicy",
      "Bypass",
      "-Command",
      [
        "$archivePath = [Environment]::GetEnvironmentVariable('VOXTYPE_ARCHIVE_PATH')",
        "$destinationPath = [Environment]::GetEnvironmentVariable('VOXTYPE_EXTRACT_PATH')",
        "Expand-Archive -LiteralPath $archivePath -DestinationPath $destinationPath -Force"
      ].join("; ")
    ], {
      env: {
        ...process.env,
        VOXTYPE_ARCHIVE_PATH: archivePath,
        VOXTYPE_EXTRACT_PATH: destination
      }
    });
  }

  private async findExecutable(runtime: WhisperRuntimeCatalogItem): Promise<string | null> {
    const runtimeDirectory = this.getRuntimeDirectory(runtime);

    for (const candidate of executableCandidates) {
      const found = await findFile(runtimeDirectory, candidate);

      if (found) {
        return found;
      }
    }

    return null;
  }

  private getRuntimeDirectory(runtime: WhisperRuntimeCatalogItem): string {
    return join(this.runtimeRootDirectory, runtime.version, runtime.id);
  }
}

async function findFile(directory: string, fileName: string): Promise<string | null> {
  try {
    const entries = await readdir(directory, { withFileTypes: true });

    for (const entry of entries) {
      const fullPath = join(directory, entry.name);

      if (entry.isFile() && entry.name.toLowerCase() === fileName.toLowerCase()) {
        return fullPath;
      }

      if (entry.isDirectory()) {
        const found = await findFile(fullPath, fileName);

        if (found) {
          return found;
        }
      }
    }
  } catch {
    return null;
  }

  return null;
}

function parseDriverMajorVersion(driverVersion?: string): number | null {
  if (!driverVersion) {
    return null;
  }

  const [major] = driverVersion.split(".");
  const parsed = Number.parseInt(major, 10);
  return Number.isFinite(parsed) ? parsed : null;
}

import { app } from "electron";
import { execFile } from "node:child_process";
import { randomUUID } from "node:crypto";
import { mkdir, readFile, rm, writeFile } from "node:fs/promises";
import { join } from "node:path";
import { promisify } from "node:util";
import {
  getDictationMode,
  isCloudDictationMode,
  type DictationMode,
  type DictationModeId
} from "../shared/asr";
import {
  assertCloudDictationLogIsMetadataOnly,
  createCloudDictationLogEntry
} from "../shared/cloud-logging";
import { getCloudFailurePolicy } from "../shared/cloud-failure-policy";
import { resolveCloudPromptPackOcrEnabled } from "../shared/cloud-prompt-pack-settings";
import {
  getCloudDictationReadinessForMode,
  profileCloudFallbackModeId,
  resolveEffectiveDictationModeId
} from "../shared/cloud-status";
import { getModelById } from "../shared/models";
import { getProviderLanguageHint } from "../shared/provider-language";
import { type OcrPromptContext } from "../shared/ocr-context";
import { findAppProfile, type AppProfile, type AppSettings } from "../shared/settings";
import { type TranscriptEntry, type TranscriptionResult } from "../shared/transcripts";
import { DictionaryStore } from "./dictionary-store";
import { HistoryStore } from "./history-store";
import { OpenAiFileAsrProvider } from "./openai-asr-provider";
import { OpenAiCredentialStore } from "./openai-credential-store";
import { buildCloudPromptPack } from "./prompt-pack";
import { RuntimeService } from "./runtime-service";
import { SettingsStore } from "./settings-store";

const execFileAsync = promisify(execFile);

export class TranscriptionService {
  constructor(
    private readonly settingsStore: SettingsStore,
    private readonly historyStore: HistoryStore,
    private readonly runtimeService: RuntimeService,
    private readonly dictionaryStore: DictionaryStore,
    private readonly openAiCredentials = new OpenAiCredentialStore(),
    private readonly openAiFileProvider = new OpenAiFileAsrProvider(openAiCredentials)
  ) {}

  async transcribeWav(
    audioBytes: Uint8Array,
    context?: {
      processName?: string | null;
      ocrContext?: OcrPromptContext | null;
      forceModeId?: "local.custom";
    }
  ): Promise<TranscriptionResult> {
    const startedAt = Date.now();
    const settings = await this.settingsStore.get();
    const profile = findAppProfile(settings.appProfiles, context?.processName ?? null);
    const mode = context?.forceModeId === "local.custom"
      ? getDictationMode("local.custom")
      : resolveDictationMode(settings, profile);
    const modelId = resolveLocalModelId(settings, mode);
    const model = getModelById(modelId);
    const whisperLanguage =
      profile?.whisperLanguage && profile.whisperLanguage !== "inherit"
        ? profile.whisperLanguage
        : settings.whisperLanguage;

    if (isCloudDictationMode(mode.id)) {
      return this.transcribeCloudFile(audioBytes, mode, settings, profile, whisperLanguage, context, startedAt);
    }

    if (!model) {
      throw new Error(`Unknown active model: ${modelId}`);
    }

    const modelPath = join(settings.modelDirectory, model.fileName);
    const executable =
      settings.whisperExecutablePath.trim() ||
      (await this.runtimeService.getExecutablePath({
        allowInstall: !settings.offlineMode,
        preference: settings.whisperRuntimeBackend
      })) ||
      "whisper-cli";
    const workDirectory = join(app.getPath("temp"), "voxtype");
    const id = randomUUID();
    const audioPath = join(workDirectory, `${id}.wav`);
    const outputBase = join(workDirectory, id);
    const outputTextPath = `${outputBase}.txt`;
    const generatedPromptContext = await this.dictionaryStore.buildPromptContext(
      context?.processName,
      context?.ocrContext?.terms
    );
    const promptContext = combinePromptContext(
      generatedPromptContext,
      settings.whisperPromptOverride
    );
    const args = [
      "-m",
      modelPath,
      "-f",
      audioPath,
      "-otxt",
      "-of",
      outputBase,
      "-np"
    ];

    if (promptContext) {
      args.push("--prompt", promptContext);
    }

    if (whisperLanguage !== "auto") {
      args.push("--language", whisperLanguage);
    }

    await mkdir(workDirectory, { recursive: true });
    await writeFile(audioPath, audioBytes);

    try {
      const { stdout } = await execFileAsync(executable, args);

      const rawText = (await readTextOutput(outputTextPath, stdout)).trim();
      const normalizedText = normalizeTranscriptText(rawText);
      const correction = await this.dictionaryStore.applyCorrections(
        normalizedText,
        context?.processName
      );
      const ocrCorrection = applyOcrTermCorrections(
        correction.text,
        context?.ocrContext?.terms ?? []
      );
      const text = ocrCorrection.text.trim();

      if (!text) {
        throw new Error("Whisper completed but returned no transcript text.");
      }

      const audioFileName = await this.historyStore.saveAudio(id, audioBytes);
      const entry: TranscriptEntry = {
        id,
        text,
        rawText: rawText !== text ? rawText : undefined,
        correctionsApplied: correction.applied.length > 0 ? correction.applied : undefined,
        ocrCorrectionsApplied:
          ocrCorrection.applied.length > 0 ? ocrCorrection.applied : undefined,
        promptContext: promptContext || undefined,
        audioFileName,
        providerId: "local-whisper",
        dictationModeId: mode.id,
        modelId: model.id,
        languageHint: getProviderLanguageHint("local-whisper", whisperLanguage).parameterValue ?? undefined,
        createdAt: new Date().toISOString(),
        durationMs: Date.now() - startedAt
      };

      await this.historyStore.add(entry);

      return { entry, promptContext: promptContext || null };
    } catch (error) {
      throw new Error(formatWhisperError(error, executable));
    } finally {
      await rm(audioPath, { force: true });
      await rm(outputTextPath, { force: true });
    }
  }

  private async transcribeCloudFile(
    audioBytes: Uint8Array,
    mode: DictationMode,
    settings: AppSettings,
    profile: AppProfile | null,
    whisperLanguage: AppSettings["whisperLanguage"],
    context: { processName?: string | null; ocrContext?: OcrPromptContext | null } | undefined,
    startedAt: number
  ): Promise<TranscriptionResult> {
    const readiness = getCloudDictationReadinessForMode({
      settings,
      profile,
      hasApiKey: await this.openAiCredentials.hasApiKey(),
      requestedModeId: mode.id
    });

    if (!readiness.ready || !readiness.cloud) {
      throw new Error(readiness.reason ?? "Cloud Dictation is not ready.");
    }

    if (mode.kind !== "file") {
      throw new Error("Realtime Cloud Dictation uses streaming capture and cannot transcribe a completed WAV file.");
    }

    const id = randomUUID();
    const promptPack = await buildCloudPromptPack(this.dictionaryStore, {
      processName: context?.processName,
      ocrContext: context?.ocrContext,
      includeOcrContext: resolveCloudPromptPackOcrEnabled(settings, profile),
      consentAccepted: settings.cloudDictationConsentAccepted
    });
    const startedLogEntry = createCloudDictationLogEntry({
      providerId: "openai",
      modelId: mode.modelId,
      modeId: mode.id,
      durationMs: 0,
      status: "started"
    });
    assertCloudDictationLogIsMetadataOnly(startedLogEntry);

    let asrResult: Awaited<ReturnType<OpenAiFileAsrProvider["transcribeFile"]>>;

    try {
      asrResult = await this.openAiFileProvider.transcribeFile({
        audioBytes,
        mode,
        promptPack,
        language: whisperLanguage
      });
    } catch (error) {
      const failedLogEntry = createCloudDictationLogEntry({
        providerId: "openai",
        modelId: mode.modelId,
        modeId: mode.id,
        durationMs: Date.now() - startedAt,
        status: "failed",
        errorCode: cloudErrorCode(error)
      });
      assertCloudDictationLogIsMetadataOnly(failedLogEntry);
      const policy = getCloudFailurePolicy(mode.id);
      throw new Error(`${policy.userMessage} ${formatErrorMessage(error)}`);
    }

    const completedLogEntry = createCloudDictationLogEntry({
      providerId: asrResult.providerId,
      modelId: asrResult.modelId,
      modeId: asrResult.modeId,
      durationMs: asrResult.durationMs,
      status: "completed"
    });
    assertCloudDictationLogIsMetadataOnly(completedLogEntry);
    const normalizedText = normalizeTranscriptText(asrResult.providerText);
    const correction = await this.dictionaryStore.applyCorrections(
      normalizedText,
      context?.processName
    );
    const text = correction.text.trim();

    if (!text) {
      throw new Error("OpenAI completed but returned no transcript text.");
    }

    const audioFileName = settings.cloudFileAudioHistoryEnabled
      ? await this.historyStore.saveAudio(id, audioBytes)
      : undefined;
    const entry: TranscriptEntry = {
      id,
      text,
      rawText: normalizedText !== text ? normalizedText : undefined,
      correctionsApplied: correction.applied.length > 0 ? correction.applied : undefined,
      audioFileName,
      providerId: asrResult.providerId,
      dictationModeId: asrResult.modeId,
      modelId: asrResult.modelId,
      languageHint: getProviderLanguageHint("openai", whisperLanguage).parameterValue ?? undefined,
      createdAt: new Date().toISOString(),
      durationMs: Date.now() - startedAt
    };

    await this.historyStore.add(entry);

    return { entry, promptContext: promptPack?.text ?? null };
  }

}

function cloudErrorCode(error: unknown): string {
  if (!(error instanceof Error)) {
    return "unknown";
  }

  const match = /\(([^)]+)\)/.exec(error.message);
  return match?.[1] ?? error.name;
}

function formatErrorMessage(error: unknown): string {
  const message = error instanceof Error ? error.message : String(error);

  if (/transcript|text/i.test(message)) {
    return "Provider returned no usable transcript.";
  }

  return message;
}

function resolveDictationMode(settings: AppSettings, profile: AppProfile | null): DictationMode {
  const requestedModeId: DictationModeId = resolveEffectiveDictationModeId(settings, profile);
  const modeId =
    profile?.forbidCloudDictation && isCloudDictationMode(requestedModeId)
      ? profileCloudFallbackModeId
      : requestedModeId;

  return getDictationMode(modeId);
}

function resolveLocalModelId(settings: AppSettings, mode: DictationMode): string {
  if (mode.id === "local.custom") {
    return settings.localCustomModelId || settings.activeModelId;
  }

  if (mode.providerId === "local-whisper") {
    return mode.modelId;
  }

  return settings.activeModelId;
}

async function readTextOutput(path: string, fallback: string): Promise<string> {
  try {
    return await readFile(path, "utf8");
  } catch {
    return fallback;
  }
}

function formatWhisperError(error: unknown, executable: string): string {
  const detail = error instanceof Error ? error.message : String(error);

  return [
    `Could not run whisper.cpp executable "${executable}".`,
    "Install/build whisper.cpp and set the whisper executable path in VoxType settings.",
    detail
  ].join(" ");
}

function normalizeTranscriptText(text: string): string {
  return text
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean)
    .join(" ")
    .replace(/\s+/g, " ")
    .trim();
}

function combinePromptContext(
  generatedPromptContext: string | null,
  promptOverride: string
): string | null {
  const generated = generatedPromptContext?.trim() ?? "";
  const custom = promptOverride.trim();

  if (!generated) {
    return custom || null;
  }

  if (!custom) {
    return generated;
  }

  if (custom.includes(generated)) {
    return custom;
  }

  return `${generated} ${custom}`;
}

function applyOcrTermCorrections(text: string, terms: string[]): {
  text: string;
  applied: string[];
} {
  let corrected = text;
  const applied: string[] = [];

  for (const term of terms.slice(0, 60)) {
    const variants = spokenVariantsForTerm(term);

    for (const variant of variants) {
      if (!variant || variant.toLowerCase() === term.toLowerCase()) {
        continue;
      }

      const next = replaceSpokenVariant(corrected, variant, term);

      if (next !== corrected) {
        corrected = next;
        applied.push(`${variant} -> ${term}`);
        break;
      }
    }
  }

  return { text: corrected, applied };
}

function spokenVariantsForTerm(term: string): string[] {
  const normalized = term.trim();

  if (normalized.length < 4 || normalized.length > 72) {
    return [];
  }

  const variants = new Set<string>();
  const separatorVariant = normalized.replace(/[._/#\\-]+/g, " ").replace(/\s+/g, " ").trim();
  const camelVariant = normalized
    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")
    .replace(/([A-Z]+)([A-Z][a-z])/g, "$1 $2")
    .replace(/\s+/g, " ")
    .trim();

  if (separatorVariant.includes(" ")) {
    variants.add(separatorVariant);
  }

  if (camelVariant.includes(" ")) {
    variants.add(camelVariant);
  }

  if (/^[A-Z]{2,6}$/.test(normalized)) {
    variants.add(normalized.split("").join(" "));
  }

  if (/^HRESULT$/i.test(normalized)) {
    variants.add("h result");
  }

  return [...variants].filter((variant) => variant.length >= 3);
}

function replaceSpokenVariant(text: string, variant: string, term: string): string {
  const escaped = variant
    .split(/\s+/)
    .map((part) => part.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"))
    .join("\\s+");
  const expression = new RegExp(`\\b${escaped}\\b`, "gi");

  return text.replace(expression, term);
}

import { app } from "electron";
import { createWriteStream } from "node:fs";
import { mkdir, rename, rm } from "node:fs/promises";
import { get } from "node:https";
import { join } from "node:path";
import { spawn } from "node:child_process";
import { type UpdateStatus } from "../shared/updates";

const latestReleaseUrl = "https://api.github.com/repos/phob/VoxType/releases/latest";
const updateRequestTimeoutMs = 15000;
const staleCheckingTimeoutMs = 30000;
const updateDirectory = join(app.getPath("userData"), "updates");

interface GitHubReleaseAsset {
  name: string;
  browser_download_url: string;
}

interface GitHubRelease {
  tag_name?: string;
  name?: string;
  html_url?: string;
  assets?: GitHubReleaseAsset[];
}

interface UpdateCandidate {
  version: string;
  releaseName: string | null;
  releaseUrl: string | null;
  installerName: string;
  installerUrl: string;
}

export class UpdateService {
  private status: UpdateStatus = {
    available: false,
    currentVersion: app.getVersion(),
    latestVersion: null,
    releaseName: null,
    releaseUrl: null,
    installerName: null,
    state: "idle",
    error: null
  };
  private candidate: UpdateCandidate | null = null;
  private checkPromise: Promise<UpdateStatus> | null = null;
  private checkingStartedAt: number | null = null;
  private readonly updateCleanupPromise: Promise<void>;

  constructor() {
    this.updateCleanupPromise = cleanupUpdateDirectory();
  }

  getStatus(): UpdateStatus {
    if (
      this.status.state === "checking" &&
      this.checkingStartedAt !== null &&
      Date.now() - this.checkingStartedAt > staleCheckingTimeoutMs
    ) {
      this.status = {
        ...this.status,
        available: false,
        state: "error",
        error: "Update check timed out."
      };
      this.checkPromise = null;
      this.checkingStartedAt = null;
    }

    return this.status;
  }

  async check(): Promise<UpdateStatus> {
    if (this.checkPromise) {
      return this.checkPromise;
    }

    this.checkPromise = this.performCheck();
    try {
      return await this.checkPromise;
    } finally {
      this.checkPromise = null;
    }
  }

  private async performCheck(): Promise<UpdateStatus> {
    this.status = {
      ...this.status,
      state: "checking",
      error: null
    };
    this.checkingStartedAt = Date.now();

    try {
      const release = await withTimeout(
        fetchJson<GitHubRelease>(latestReleaseUrl),
        updateRequestTimeoutMs,
        "Update check timed out."
      );
      const candidate = releaseToCandidate(release);
      const currentVersion = app.getVersion();
      const available = Boolean(candidate && isNewerVersion(candidate.version, currentVersion));

      this.candidate = available ? candidate : null;
      this.status = {
        available,
        currentVersion,
        latestVersion: candidate?.version ?? null,
        releaseName: candidate?.releaseName ?? null,
        releaseUrl: candidate?.releaseUrl ?? null,
        installerName: candidate?.installerName ?? null,
        state: available ? "available" : "idle",
        error: null
      };
    } catch (error) {
      this.status = {
        ...this.status,
        available: false,
        state: "error",
        error: formatUpdateError(error)
      };
    } finally {
      this.checkingStartedAt = null;
    }

    return this.status;
  }

  async install(): Promise<UpdateStatus> {
    const candidate = this.candidate ?? (await this.check(), this.candidate);

    if (!candidate) {
      return this.status;
    }

    if (process.platform !== "win32") {
      throw new Error("Automatic installer updates are currently only supported on Windows.");
    }

    this.status = {
      ...this.status,
      state: "downloading",
      error: null
    };

    let temporaryInstallerPath: string | null = null;

    try {
      await this.updateCleanupPromise;
      const installerPath = join(updateDirectory, candidate.installerName);
      temporaryInstallerPath = `${installerPath}.download`;

      await mkdir(updateDirectory, { recursive: true });
      await rm(temporaryInstallerPath, { force: true });
      await downloadFile(candidate.installerUrl, temporaryInstallerPath);
      await rm(installerPath, { force: true });
      await rename(temporaryInstallerPath, installerPath);

      this.status = {
        ...this.status,
        state: "installing"
      };

      const child = spawn(installerPath, [], {
        detached: true,
        stdio: "ignore"
      });
      child.unref();

      app.quit();
    } catch (error) {
      if (temporaryInstallerPath) {
        await rm(temporaryInstallerPath, { force: true }).catch(() => undefined);
      }

      this.status = {
        ...this.status,
        state: "error",
        error: formatUpdateError(error)
      };
    }

    return this.status;
  }
}

async function cleanupUpdateDirectory(): Promise<void> {
  await rm(updateDirectory, { recursive: true, force: true }).catch(() => undefined);
}

function releaseToCandidate(release: GitHubRelease): UpdateCandidate | null {
  const version = versionFromTag(release.tag_name);
  const installer = release.assets?.find((asset) =>
    /^VoxType-Setup-.+-x64\.exe$/i.test(asset.name)
  );

  if (!version || !installer?.browser_download_url) {
    return null;
  }

  return {
    version,
    releaseName: release.name ?? null,
    releaseUrl: release.html_url ?? null,
    installerName: installer.name,
    installerUrl: installer.browser_download_url
  };
}

function versionFromTag(tag: string | undefined): string | null {
  const normalized = tag?.trim().replace(/^voxtype-/i, "").replace(/^v/i, "");
  return normalized && /^\d+\.\d+\.\d+(?:[-+][0-9A-Za-z.-]+)?$/.test(normalized)
    ? normalized
    : null;
}

function isNewerVersion(candidate: string, current: string): boolean {
  const candidateParts = parseVersion(candidate);
  const currentParts = parseVersion(current);

  for (let index = 0; index < 3; index += 1) {
    if (candidateParts[index] > currentParts[index]) {
      return true;
    }

    if (candidateParts[index] < currentParts[index]) {
      return false;
    }
  }

  return false;
}

function parseVersion(version: string): [number, number, number] {
  const stableVersion = version.replace(/^voxtype-/i, "").replace(/^v/i, "").replace(/[-+].*$/, "");
  const [major = "0", minor = "0", patch = "0"] = stableVersion.split(".");
  return [Number(major) || 0, Number(minor) || 0, Number(patch) || 0];
}

function fetchJson<T>(url: string): Promise<T> {
  return new Promise((resolve, reject) => {
    let settled = false;
    const resolveOnce = (value: T): void => {
      if (settled) {
        return;
      }

      settled = true;
      resolve(value);
    };
    const rejectOnce = (error: unknown): void => {
      if (settled) {
        return;
      }

      settled = true;
      reject(error);
    };
    const request = get(
      url,
      {
        headers: {
          Accept: "application/vnd.github+json",
          "Cache-Control": "no-cache",
          Pragma: "no-cache",
          "User-Agent": "VoxType-Updater"
        }
      },
      (response) => {
        response.setTimeout(updateRequestTimeoutMs, () => {
          response.destroy(new Error("Update check timed out."));
        });

        if (response.statusCode && response.statusCode >= 300 && response.statusCode < 400) {
          const redirect = response.headers.location;
          response.resume();
          if (redirect) {
            fetchJson<T>(redirect).then(resolveOnce, rejectOnce);
            return;
          }
        }

        if (response.statusCode !== 200) {
          response.resume();
          rejectOnce(new Error(`GitHub returned ${response.statusCode ?? "an unknown status"}.`));
          return;
        }

        let body = "";
        response.setEncoding("utf8");
        response.on("data", (chunk) => {
          body += chunk;
        });
        response.on("end", () => {
          try {
            resolveOnce(JSON.parse(body) as T);
          } catch (error) {
            rejectOnce(error);
          }
        });
        response.on("error", rejectOnce);
      }
    );

    request.setTimeout(updateRequestTimeoutMs, () => {
      request.destroy(new Error("Update check timed out."));
    });
    request.on("error", rejectOnce);
  });
}

function withTimeout<T>(promise: Promise<T>, timeoutMs: number, message: string): Promise<T> {
  return new Promise((resolve, reject) => {
    const timer = setTimeout(() => {
      reject(new Error(message));
    }, timeoutMs);

    promise.then(
      (value) => {
        clearTimeout(timer);
        resolve(value);
      },
      (error) => {
        clearTimeout(timer);
        reject(error);
      }
    );
  });
}

function downloadFile(url: string, destination: string): Promise<void> {
  return new Promise((resolve, reject) => {
    const request = get(
      url,
      {
        headers: {
          "User-Agent": "VoxType-Updater"
        }
      },
      (response) => {
        if (response.statusCode && response.statusCode >= 300 && response.statusCode < 400) {
          const redirect = response.headers.location;
          response.resume();
          if (redirect) {
            downloadFile(redirect, destination).then(resolve, reject);
            return;
          }
        }

        if (response.statusCode !== 200) {
          response.resume();
          reject(new Error(`Download returned ${response.statusCode ?? "an unknown status"}.`));
          return;
        }

        const file = createWriteStream(destination);
        response.pipe(file);
        file.on("finish", () => {
          file.close(() => { resolve(); });
        });
        file.on("error", reject);
      }
    );

    request.on("error", reject);
  });
}

function formatUpdateError(error: unknown): string {
  return error instanceof Error ? error.message : String(error);
}

import { app } from "electron";
import { type ChildProcessWithoutNullStreams, execFile, spawn } from "node:child_process";
import { access, mkdir, readFile, rm, stat } from "node:fs/promises";
import { join, resolve } from "node:path";
import { promisify } from "node:util";
import {
  type ActiveWindowInfo,
  type CaptureSessionMuteState,
  type NativeRecordingLevel,
  type NativeRecordingOptions,
  type NativeRecordingResult,
  type NativeInputDevice,
  type WindowsMediaOcrResult,
  type ScreenshotCaptureMode,
  type ScreenshotCaptureResult,
  type WindowsHelperStatus
} from "../shared/windows-helper";
import { retainLatestFiles } from "./file-retention";

const execFileAsync = promisify(execFile);
const retainedScreenshotCount = 10;

interface NativeRecording {
  child: ChildProcessWithoutNullStreams;
  outputPath: string;
  stdout: Buffer[];
  stderr: Buffer[];
}

export class WindowsHelperService {
  private recording: NativeRecording | null = null;

  async getStatus(): Promise<WindowsHelperStatus> {
    const helperPath = await this.resolveHelperPath();
    const helperStats = helperPath ? await stat(helperPath).catch(() => null) : null;

    return {
      available: Boolean(helperPath),
      helperPath,
      helperModifiedAt: helperStats?.mtime.toISOString() ?? null,
      helperCreatedAt: helperStats?.birthtime.toISOString() ?? null,
      helperSizeBytes: helperStats?.size ?? null,
      error: helperPath ? null : "Windows helper executable was not found."
    };
  }

  async getActiveWindow(): Promise<ActiveWindowInfo> {
    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    const { stdout } = await execFileAsync(helperPath, ["active-window"], {
      windowsHide: true
    });
    const parsed = JSON.parse(stdout) as unknown;

    if (!isActiveWindowInfo(parsed)) {
      throw new Error("Windows helper returned an unexpected active-window payload.");
    }

    return normalizeActiveWindowInfo(parsed);
  }

  async pasteText(pasteDelayMs = 0): Promise<void> {
    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    await execFileAsync(helperPath, ["paste-text", String(pasteDelayMs)], {
      windowsHide: true
    });
  }

  async typeText(text: string, delayMs: number): Promise<void> {
    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    await runHelperWithStdin(helperPath, ["type-text", String(delayMs)], text);
  }

  async messageText(
    text: string,
    strategy: "focused-control" | "character-messages",
    hwnd?: string | null
  ): Promise<void> {
    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    const args = ["message-text", strategy];

    if (hwnd) {
      args.push(hwnd);
    }

    await runHelperWithStdin(helperPath, args, text);
  }

  async focusWindow(hwnd: string): Promise<void> {
    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    await execFileAsync(helperPath, ["focus-window", hwnd], {
      windowsHide: true
    });
  }

  async setSystemMute(muted: boolean): Promise<void> {
    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    await execFileAsync(helperPath, ["set-system-mute", muted ? "true" : "false"], {
      windowsHide: true
    });
  }

  async sendHotkey(accelerator: string): Promise<void> {
    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    if (!accelerator.trim()) {
      throw new Error("Recording coordination hotkey is empty.");
    }

    await execFileAsync(helperPath, ["send-hotkey", accelerator], {
      windowsHide: true
    });
  }

  async waitForHotkeyRelease(accelerator: string): Promise<void> {
    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    if (!accelerator.trim()) {
      throw new Error("Hold hotkey is empty.");
    }

    await execFileAsync(helperPath, ["wait-hotkey-release", accelerator], {
      windowsHide: true
    });
  }

  async captureScreenshot(
    mode: ScreenshotCaptureMode,
    targetHwnd?: string | null
  ): Promise<ScreenshotCaptureResult> {
    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    const outputDirectory = join(app.getPath("userData"), "screenshots");
    await mkdir(outputDirectory, { recursive: true });
    const outputPath = join(outputDirectory, `screenshot-${Date.now()}.png`);
    const args = ["capture-screenshot", outputPath];

    if (mode === "activeWindow") {
      args.push("--active-window");
    }

    if (targetHwnd) {
      args.push("--hwnd", targetHwnd);
    }

    await execFileAsync(helperPath, args, {
      windowsHide: true
    });

    await retainLatestFiles(
      outputDirectory,
      retainedScreenshotCount,
      (fileName) => /^screenshot-\d+\.png$/i.test(fileName)
    );

    return {
      path: outputPath,
      bytes: new Uint8Array(await readFile(outputPath)),
      capturedAt: new Date().toISOString(),
      mode
    };
  }

  async recognizeImageText(imagePath: string): Promise<WindowsMediaOcrResult> {
    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    const { stdout } = await execFileAsync(helperPath, ["ocr-image", imagePath], {
      windowsHide: true
    });
    const parsed = JSON.parse(stdout) as unknown;

    if (!isWindowsMediaOcrResult(parsed)) {
      throw new Error("Windows helper returned an unexpected Windows OCR payload.");
    }

    return parsed;
  }

  async muteCaptureSession(
    processId: number,
    processName?: string | null
  ): Promise<CaptureSessionMuteState> {
    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    const args = ["mute-capture-session", String(processId)];

    if (processName) {
      args.push(processName);
    }

    const { stdout } = await execFileAsync(helperPath, args, {
      windowsHide: true
    });
    const parsed = JSON.parse(stdout) as unknown;

    if (!isCaptureSessionMuteState(parsed)) {
      throw new Error("Windows helper returned an unexpected capture-session mute payload.");
    }

    return parsed;
  }

  async restoreCaptureSession(state: CaptureSessionMuteState): Promise<void> {
    if (state.sessions.length === 0) {
      return;
    }

    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    await runHelperWithStdin(helperPath, ["restore-capture-session"], JSON.stringify(state));
  }

  async listInputDevices(): Promise<NativeInputDevice[]> {
    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    const { stdout } = await execFileAsync(helperPath, ["input-devices"], {
      windowsHide: true
    });
    const parsed = JSON.parse(stdout) as unknown;

    if (!Array.isArray(parsed) || !parsed.every(isNativeInputDevice)) {
      throw new Error("Windows helper returned an unexpected input-devices payload.");
    }

    return parsed;
  }

  async startRecording(
    options: NativeRecordingOptions,
    onLevel?: (level: NativeRecordingLevel, pcm16Chunk?: Uint8Array) => void
  ): Promise<void> {
    if (this.recording) {
      throw new Error("Native recording is already active.");
    }

    const helperPath = await this.resolveHelperPath();

    if (!helperPath) {
      throw new Error(
        "Windows helper executable was not found. Build it with `cargo build --manifest-path native/windows-helper/Cargo.toml`."
      );
    }

    const outputDirectory = join(app.getPath("userData"), "native-recordings");
    await mkdir(outputDirectory, { recursive: true });
    const outputPath = join(outputDirectory, `recording-${Date.now()}.wav`);
    const args = ["record-wav", outputPath];
    const vadModelPath = await this.resolveSileroVadModelPath();
    const captureModeArg = nativeCaptureModeArg(options.captureMode);

    if (captureModeArg) {
      args.push("--capture-mode", captureModeArg);
    }

    if (options.inputDeviceId && options.inputDeviceId !== "default") {
      args.push("--input-device", options.inputDeviceId);
    }

    if (options.vadEnabled) {
      if (!vadModelPath) {
        throw new Error("Silero VAD model was not found.");
      }

      args.push(
        "--vad-model",
        vadModelPath,
        "--vad-threshold",
        String(options.vadPositiveSpeechThreshold),
        "--vad-prefill-frames",
        String(msToVadFrames(options.vadPreSpeechPadMs)),
        "--vad-hangover-frames",
        String(msToVadFrames(options.vadRedemptionMs)),
        "--vad-preserved-pause-frames",
        String(msToVadFrames(options.vadPreservedPauseMs)),
        "--vad-onset-frames",
        "2"
      );
    }

    const child = spawn(helperPath, args, {
      stdio: ["pipe", "pipe", "pipe"],
      windowsHide: true
    });
    const stdout: Buffer[] = [];
    const stderr: Buffer[] = [];
    let stdoutRemainder = "";

    child.stdout.on("data", (chunk: Buffer) => {
      const { complete, remainder } = splitCompleteStdoutLines(`${stdoutRemainder}${chunk.toString("utf8")}`);
      stdoutRemainder = remainder;
      stdout.push(Buffer.from(stripRealtimePcm16ChunkEvents(complete)));
      for (const event of parseRecordingStdoutEvents(complete)) {
        onLevel?.(event.level, event.pcm16Chunk);
      }
    });
    child.stderr.on("data", (chunk: Buffer) => stderr.push(chunk));
    child.once("close", () => {
      const complete = stdoutRemainder;
      stdoutRemainder = "";
      stdout.push(Buffer.from(stripRealtimePcm16ChunkEvents(complete)));
      for (const event of parseRecordingStdoutEvents(complete)) {
        onLevel?.(event.level, event.pcm16Chunk);
      }
    });
    child.once("exit", (code) => {
      if (this.recording?.child === child && code !== null && code !== 0) {
        this.recording = null;
      }
    });

    this.recording = {
      child,
      outputPath,
      stdout,
      stderr
    };

    try {
      await waitForHelperStartup(child, stdout, stderr);
    } catch (error) {
      if (this.recording?.child === child) {
        this.recording = null;
      }

      child.kill();
      await rm(outputPath, { force: true });

      if (
        options.captureMode === "exclusiveCapturePreferred" &&
        errorMessage(error).includes("Exclusive microphone capture failed")
      ) {
        return this.startRecording({
          ...options,
          captureMode: "sharedCapture"
        });
      }

      throw error;
    }
  }

  async stopRecording(): Promise<NativeRecordingResult> {
    const recording = this.recording;

    if (!recording) {
      throw new Error("Native recording is not active.");
    }

    this.recording = null;
    recording.child.stdin.end("stop\n", "utf8");

    await new Promise<void>((resolvePromise, reject) => {
      recording.child.once("error", reject);
      recording.child.once("close", (code) => {
        if (code === 0) {
          resolvePromise();
          return;
        }

        const message =
          Buffer.concat(recording.stdout).toString("utf8").trim() ||
          Buffer.concat(recording.stderr).toString("utf8").trim() ||
          `Windows helper exited with code ${code}.`;

        reject(new Error(message));
      });
    });

    const bytes = await readFile(recording.outputPath);
    const metadata = parseNativeRecordingMetadata(
      Buffer.concat(recording.stdout).toString("utf8")
    );
    await rm(recording.outputPath, { force: true });
    return {
      wavBytes: new Uint8Array(bytes),
      ...metadata
    };
  }

  private async resolveHelperPath(): Promise<string | null> {
    const candidates = [
      process.env.VOXTYPE_WINDOWS_HELPER_PATH,
      resolve("native/windows-helper/target/debug/voxtype-windows-helper.exe"),
      resolve("native/windows-helper/target/release/voxtype-windows-helper.exe"),
      join(process.resourcesPath, "native", "voxtype-windows-helper.exe"),
      join(app.getAppPath(), "native", "voxtype-windows-helper.exe")
    ].filter((candidate): candidate is string => Boolean(candidate));

    for (const candidate of candidates) {
      if (await fileExists(candidate)) {
        return candidate;
      }
    }

    return null;
  }

  private async resolveSileroVadModelPath(): Promise<string | null> {
    const candidates = [
      process.env.VOXTYPE_SILERO_VAD_MODEL_PATH,
      resolve("resources/models/silero_vad_v4.onnx"),
      join(process.resourcesPath, "models", "silero_vad_v4.onnx"),
      join(app.getAppPath(), "resources", "models", "silero_vad_v4.onnx")
    ].filter((candidate): candidate is string => Boolean(candidate));

    for (const candidate of candidates) {
      if (await fileExists(candidate)) {
        return candidate;
      }
    }

    return null;
  }
}

function isWindowsMediaOcrResult(value: unknown): value is WindowsMediaOcrResult {
  if (typeof value !== "object" || value === null || Array.isArray(value)) {
    return false;
  }

  const result = value as Record<string, unknown>;

  return (
    result.provider === "windowsMediaOcr" &&
    typeof result.engine === "string" &&
    typeof result.imagePath === "string" &&
    typeof result.text === "string" &&
    typeof result.durationMs === "number" &&
    Array.isArray(result.lines) &&
    result.lines.every((line) => {
      if (typeof line !== "object" || line === null || Array.isArray(line)) {
        return false;
      }

      const entry = line as Record<string, unknown>;

      return (
        typeof entry.text === "string" &&
        (typeof entry.confidence === "number" || entry.confidence === null) &&
        (entry.box === null ||
          (Array.isArray(entry.box) &&
            entry.box.length === 4 &&
            entry.box.every((item) => typeof item === "number")))
      );
    })
  );
}

function msToVadFrames(milliseconds: number): number {
  return Math.max(0, Math.round(milliseconds / 30));
}

function parseNativeRecordingMetadata(stdout: string): Omit<NativeRecordingResult, "wavBytes"> {
  const line = stdout
    .split(/\r?\n/)
    .map((item) => item.trim())
    .filter((item) => Boolean(item) && !isRecordingLevelLine(item))
    .at(-1);

  if (!line) {
    throw new Error("Windows helper did not return recording metadata.");
  }

  const parsed = JSON.parse(line) as Record<string, unknown>;

  return {
    sampleRate: typeof parsed.sampleRate === "number" ? parsed.sampleRate : 16000,
    samples: typeof parsed.samples === "number" ? parsed.samples : 0,
    rawSamples: typeof parsed.rawSamples === "number" ? parsed.rawSamples : 0,
    vadEnabled: typeof parsed.vadEnabled === "boolean" ? parsed.vadEnabled : false,
    captureMode:
      parsed.captureMode === "exclusiveCapture" ? "exclusiveCapture" : "sharedCapture",
    speechFrames: typeof parsed.speechFrames === "number" ? parsed.speechFrames : 0
  };
}

function parseRecordingLevelEvents(stdout: string): NativeRecordingLevel[] {
  return parseRecordingStdoutEvents(stdout).map((event) => event.level);
}

function splitCompleteStdoutLines(stdout: string): { complete: string; remainder: string } {
  const lastNewlineIndex = Math.max(stdout.lastIndexOf("\n"), stdout.lastIndexOf("\r"));

  if (lastNewlineIndex < 0) {
    return { complete: "", remainder: stdout };
  }

  return {
    complete: stdout.slice(0, lastNewlineIndex + 1),
    remainder: stdout.slice(lastNewlineIndex + 1)
  };
}

function stripRealtimePcm16ChunkEvents(stdout: string): string {
  return stdout
    .split(/\r?\n/)
    .filter((line) => {
      try {
        const parsed = JSON.parse(line) as Record<string, unknown>;
        return parsed.type !== "realtimePcm16Chunk";
      } catch {
        return true;
      }
    })
    .join("\n");
}

function parseRecordingStdoutEvents(stdout: string): {
  level: NativeRecordingLevel;
  pcm16Chunk?: Uint8Array;
}[] {
  return stdout
    .split(/\r?\n/)
    .map((item) => item.trim())
    .filter(Boolean)
    .flatMap((line) => {
      try {
        const parsed = JSON.parse(line) as Record<string, unknown>;

        if (parsed.type === "recordingLevel") {
          return [{
            level: {
              rms: typeof parsed.rms === "number" ? clamp01(parsed.rms) : 0,
              peak: typeof parsed.peak === "number" ? clamp01(parsed.peak) : 0
            }
          }];
        }

        if (
          parsed.type === "realtimePcm16Chunk" &&
          parsed.encoding === "pcm16" &&
          parsed.sampleRateHz === 24000 &&
          parsed.channelCount === 1 &&
          typeof parsed.audioBase64 === "string"
        ) {
          const pcm16Chunk = new Uint8Array(Buffer.from(parsed.audioBase64, "base64"));

          if (pcm16Chunk.byteLength === 0 || pcm16Chunk.byteLength % 2 !== 0) {
            return [];
          }

          return [{
            level: { rms: 0, peak: 0 },
            pcm16Chunk
          }];
        }
      } catch {
        return [];
      }

      return [];
    });
}

function isRecordingLevelLine(line: string): boolean {
  try {
    const parsed = JSON.parse(line) as Record<string, unknown>;
    return parsed.type === "recordingLevel";
  } catch {
    return false;
  }
}

function clamp01(value: number): number {
  return Math.min(Math.max(value, 0), 1);
}

function nativeCaptureModeArg(mode: NativeRecordingOptions["captureMode"]): string | null {
  if (mode === "exclusiveCapturePreferred") {
    return "exclusive-preferred";
  }

  if (mode === "exclusiveCaptureRequired") {
    return "exclusive-required";
  }

  return null;
}

function errorMessage(error: unknown): string {
  return error instanceof Error ? error.message : String(error);
}

function waitForHelperStartup(
  child: ChildProcessWithoutNullStreams,
  stdout: Buffer[],
  stderr: Buffer[]
): Promise<void> {
  return new Promise((resolvePromise, reject) => {
    const startupTimeout = setTimeout(() => {
      cleanup();
      resolvePromise();
    }, 250);

    const handleError = (error: Error): void => {
      cleanup();
      reject(error);
    };

    const handleExit = (code: number | null): void => {
      cleanup();
      const message =
        Buffer.concat(stdout).toString("utf8").trim() ||
        Buffer.concat(stderr).toString("utf8").trim() ||
        `Windows helper exited before recording started with code ${code}.`;

      reject(new Error(message));
    };

    const cleanup = (): void => {
      clearTimeout(startupTimeout);
      child.off("error", handleError);
      child.off("exit", handleExit);
    };

    child.once("error", handleError);
    child.once("exit", handleExit);
  });
}

function runHelperWithStdin(
  helperPath: string,
  args: string[],
  stdin: string
): Promise<void> {
  return new Promise((resolvePromise, reject) => {
    const child = spawn(helperPath, args, {
      stdio: ["pipe", "pipe", "pipe"],
      windowsHide: true
    });
    const stdout: Buffer[] = [];
    const stderr: Buffer[] = [];

    child.stdout.on("data", (chunk: Buffer) => stdout.push(chunk));
    child.stderr.on("data", (chunk: Buffer) => stderr.push(chunk));
    child.on("error", reject);
    child.on("close", (code) => {
      if (code === 0) {
        resolvePromise();
        return;
      }

      const message =
        Buffer.concat(stdout).toString("utf8").trim() ||
        Buffer.concat(stderr).toString("utf8").trim() ||
        `Windows helper exited with code ${code}.`;

      reject(new Error(message));
    });

    child.stdin.end(stdin, "utf8");
  });
}

async function fileExists(path: string): Promise<boolean> {
  try {
    await access(path);
    return true;
  } catch {
    return false;
  }
}

function isActiveWindowInfo(value: unknown): value is ActiveWindowInfo {
  if (typeof value !== "object" || value === null || Array.isArray(value)) {
    return false;
  }

  const info = value as Record<string, unknown>;

  return (
    typeof info.hwnd === "string" &&
    typeof info.title === "string" &&
    typeof info.processId === "number" &&
    (typeof info.processPath === "string" || info.processPath === null) &&
    (typeof info.processName === "string" || info.processName === null) &&
    (info.bounds === undefined || info.bounds === null || isWindowBounds(info.bounds)) &&
    (info.fullscreen === undefined || typeof info.fullscreen === "boolean")
  );
}

function normalizeActiveWindowInfo(value: ActiveWindowInfo): ActiveWindowInfo {
  return {
    ...value,
    bounds: value.bounds ?? null,
    fullscreen: value.fullscreen
  };
}

function isWindowBounds(value: unknown): boolean {
  if (typeof value !== "object" || value === null || Array.isArray(value)) {
    return false;
  }

  const bounds = value as Record<string, unknown>;

  return (
    typeof bounds.left === "number" &&
    typeof bounds.top === "number" &&
    typeof bounds.right === "number" &&
    typeof bounds.bottom === "number" &&
    typeof bounds.width === "number" &&
    typeof bounds.height === "number"
  );
}

function isNativeInputDevice(value: unknown): value is NativeInputDevice {
  if (typeof value !== "object" || value === null || Array.isArray(value)) {
    return false;
  }

  const device = value as Record<string, unknown>;

  return (
    typeof device.id === "string" &&
    typeof device.name === "string" &&
    typeof device.isDefault === "boolean"
  );
}

function isCaptureSessionMuteState(value: unknown): value is CaptureSessionMuteState {
  if (typeof value !== "object" || value === null || Array.isArray(value)) {
    return false;
  }

  const state = value as Record<string, unknown>;

  return (
    Array.isArray(state.sessions) &&
    state.sessions.every((session) => {
      if (typeof session !== "object" || session === null || Array.isArray(session)) {
        return false;
      }

      const entry = session as Record<string, unknown>;

      return (
        typeof entry.sessionInstanceIdentifier === "string" &&
        typeof entry.processId === "number" &&
        (typeof entry.processName === "string" || entry.processName === null) &&
        typeof entry.mutedBefore === "boolean"
      );
    })
  );
}

