                  max={5000}
                  min={50}
                  type="number"
                  value={state.settings.vadMinSpeechMs}
                  onChange={(event) => void updateSettings({ vadMinSpeechMs: Number(event.target.value) })}
                />
              </label>
              <label className="dev-field">
