  shouldWarn: boolean;
  shouldStop: boolean;
  warningMessage: string | null;
}

export function getCloudSessionLimitState(input: {
  settings: AppSettings;
  modeId: DictationModeId;
  startedAtMs: number;
  nowMs: number;
}): CloudSessionLimitState {
  const cloud = isCloudDictationMode(input.modeId);
  const elapsedMs = Math.max(0, input.nowMs - input.startedAtMs);

  if (!cloud) {
    return { cloud, elapsedMs, shouldWarn: false, shouldStop: false, warningMessage: null };
  }

  const maxSessionMs = input.settings.cloudSessionMaxMs;
  const unlimited = maxSessionMs === null;
  const shouldStop = maxSessionMs !== null && elapsedMs >= maxSessionMs;
  const shouldWarn = !shouldStop && elapsedMs >= input.settings.cloudSessionWarnMs;

  return {
    cloud,
    elapsedMs,
    shouldWarn,
    shouldStop,
    warningMessage: shouldStop
      ? "Cloud Dictation reached the maximum session duration and will finalize now."
      : shouldWarn
        ? "Cloud Dictation has been active for more than 5 minutes."
        : null
  };
}

export type DictionaryEntrySource = "user" | "correction" | "ocr";

export interface DictionaryEntry {
  id: string;
  preferred: string;
  matches: string[];
  category: string;
  appProcessName: string | null;
  source: DictionaryEntrySource;
  enabled: boolean;
  createdAt: string;
  updatedAt: string;
}

export type DictionaryPatch = Partial<
  Pick<
    DictionaryEntry,
    "preferred" | "matches" | "category" | "appProcessName" | "source" | "enabled"
  >
>;

export type DictionaryCreateInput = Pick<DictionaryEntry, "preferred"> &
  Partial<
    Pick<DictionaryEntry, "matches" | "category" | "appProcessName" | "source" | "enabled">
  >;

export function sanitizeDictionaryEntries(value: unknown): DictionaryEntry[] {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.filter(isDictionaryEntry).map((entry) => ({
    ...entry,
    preferred: entry.preferred.trim(),
    matches: uniqueStrings(entry.matches.map((match) => match.trim()).filter(Boolean)),
    category: entry.category.trim(),
    appProcessName: normalizeNullableString(entry.appProcessName),
    updatedAt: entry.updatedAt || entry.createdAt
  }));
}

export function normalizeDictionaryCreateInput(
  input: DictionaryCreateInput
): Omit<DictionaryEntry, "id" | "createdAt" | "updatedAt"> {
  return {
    preferred: input.preferred.trim(),
    matches: uniqueStrings((input.matches ?? []).map((match) => match.trim()).filter(Boolean)),
    category: input.category?.trim() || "general",
    appProcessName: normalizeNullableString(input.appProcessName ?? null),
    source: input.source ?? "user",
    enabled: input.enabled ?? true
  };
}

export function normalizeDictionaryPatch(patch: DictionaryPatch): DictionaryPatch {
  return omitUndefined({
    ...patch,
    preferred: patch.preferred?.trim(),
    matches: patch.matches
      ? uniqueStrings(patch.matches.map((match) => match.trim()).filter(Boolean))
      : undefined,
    category: patch.category?.trim(),
    appProcessName:
      patch.appProcessName === undefined
        ? undefined
        : normalizeNullableString(patch.appProcessName)
  });
}

function isDictionaryEntry(value: unknown): value is DictionaryEntry {
  if (typeof value !== "object" || value === null || Array.isArray(value)) {
    return false;
  }

  const entry = value as Record<string, unknown>;

  return (
    typeof entry.id === "string" &&
    typeof entry.preferred === "string" &&
    Array.isArray(entry.matches) &&
    entry.matches.every((match) => typeof match === "string") &&
    typeof entry.category === "string" &&
    (typeof entry.appProcessName === "string" || entry.appProcessName === null) &&
    isDictionaryEntrySource(entry.source) &&
    typeof entry.enabled === "boolean" &&
    typeof entry.createdAt === "string" &&
    typeof entry.updatedAt === "string"
  );
}

function isDictionaryEntrySource(value: unknown): value is DictionaryEntrySource {
  return value === "user" || value === "correction" || value === "ocr";
}

function normalizeNullableString(value: string | null | undefined): string | null {
  return typeof value === "string" && value.trim() ? value.trim().toLowerCase() : null;
}

function uniqueStrings(values: string[]): string[] {
  return [...new Set(values)];
}

function omitUndefined<T extends Record<string, unknown>>(value: T): Partial<T> {
  return Object.fromEntries(
    Object.entries(value).filter(([, entryValue]) => entryValue !== undefined)
  ) as Partial<T>;
}

import { whisperModelCatalog } from "./models";

export type GpuVendor = "nvidia" | "amd" | "intel" | "unknown";

export interface GpuDevice {
  name: string;
  vendor: GpuVendor;
  dedicatedVramMb: number | null;
  driverVersion?: string;
  source: "nvidia-smi" | "windows-video-controller";
  supportsCuda: boolean;
  supportsVulkan: boolean | null;
}

export interface ModelGpuFit {
  modelId: string;
  requiredVramMb: number;
  status: "fits" | "low-vram" | "unknown-vram" | "no-gpu";
  note: string;
}

export interface HardwareAccelerationReport {
  checkedAt: string;
  gpus: GpuDevice[];
  bestGpu: GpuDevice | null;
  canUseGpuRuntime: boolean;
  recommendedBackend: "cuda" | "vulkan" | "cpu";
  modelFits: ModelGpuFit[];
  notes: string[];
}

const vramSafetyMarginMb = 512;

export function buildHardwareAccelerationReport(gpus: GpuDevice[]): HardwareAccelerationReport {
  const bestGpu = [...gpus].sort((left, right) => {
    const leftVram = left.dedicatedVramMb ?? -1;
    const rightVram = right.dedicatedVramMb ?? -1;
    return rightVram - leftVram;
  })[0] ?? null;
  const recommendedBackend = bestGpu?.supportsCuda
    ? "cuda"
    : bestGpu?.supportsVulkan
      ? "vulkan"
      : "cpu";
  const canUseGpuRuntime = recommendedBackend !== "cpu";

  return {
    checkedAt: new Date().toISOString(),
    gpus,
    bestGpu,
    canUseGpuRuntime,
    recommendedBackend,
    modelFits: whisperModelCatalog.map((model) => {
      const requiredVramMb = model.minimumVramMb + vramSafetyMarginMb;

      if (!bestGpu) {
        return {
          modelId: model.id,
          requiredVramMb,
          status: "no-gpu",
          note: "No supported GPU was detected."
        };
      }

      if (bestGpu.dedicatedVramMb === null) {
        return {
          modelId: model.id,
          requiredVramMb,
          status: "unknown-vram",
          note: "GPU detected, but VRAM could not be read."
        };
      }

      const fits = bestGpu.dedicatedVramMb >= requiredVramMb;

      return {
        modelId: model.id,
        requiredVramMb,
        status: fits ? "fits" : "low-vram",
        note: fits
          ? `Fits ${bestGpu.name} with a ${vramSafetyMarginMb} MB safety margin.`
          : `Needs about ${requiredVramMb} MB VRAM including safety margin.`
      };
    }),
    notes: [
      "Whisper GPU use requires a GPU-enabled runtime binary; the current managed VoxType runtime is CPU-only.",
      "CUDA is preferred for NVIDIA GPUs. Vulkan is the cross-vendor fallback once VoxType ships a Vulkan build.",
      "VRAM checks are conservative estimates for model loading, not a promise of exact throughput."
    ]
  };
}

export type OpenAiErrorCategory =
  | "invalid_key"
  | "billing"
  | "rate_limit"
  | "model_access"
  | "api_shape"
  | "network"
  | "unknown";

export interface OpenAiFriendlyError {
  category: OpenAiErrorCategory;
  summary: string;
  technicalDetail: string;
}

export function classifyOpenAiError(input: {
  status?: number;
  statusText?: string;
  type?: string | null;
  code?: string | null;
  message?: string | null;
}): OpenAiFriendlyError {
  const providerMessage = sanitizeOpenAiErrorMessage(input.message);
  const detail = [input.status, input.statusText, input.type, input.code, providerMessage]
    .filter((part) => part !== undefined && part !== null && String(part).trim())
    .join(" / ");
  const haystack = `${input.status ?? ""} ${input.type ?? ""} ${input.code ?? ""} ${input.message ?? ""}`.toLowerCase();

  if (input.status === 401 || haystack.includes("invalid_api_key")) {
    return {
      category: "invalid_key",
      summary: "OpenAI rejected the API key. Check that the key is copied correctly.",
      technicalDetail: detail || "401"
    };
  }

  if (input.status === 402 || haystack.includes("billing") || haystack.includes("insufficient_quota")) {
    return {
      category: "billing",
      summary: "OpenAI billing or quota is not available for this API key.",
      technicalDetail: detail || "billing"
    };
  }

  if (input.status === 429 || haystack.includes("rate_limit")) {
    return {
      category: "rate_limit",
      summary: "OpenAI rate limits were reached. Try again later or check your usage limits.",
      technicalDetail: detail || "429"
    };
  }

  if (
    haystack.includes("beta_api_shape_disabled") ||
    (haystack.includes("invalid_request_error") &&
      (haystack.includes("invalid_model") ||
        haystack.includes("invalid_parameter") ||
        haystack.includes("unsupported") ||
        haystack.includes("unknown parameter") ||
        haystack.includes("unexpected")))
  ) {
    return {
      category: "api_shape",
      summary: "OpenAI rejected the Realtime API request shape. Update VoxType or switch to a supported cloud mode.",
      technicalDetail: detail || "api_shape"
    };
  }

  if (input.status === 404 || haystack.includes("model") || haystack.includes("access")) {
    return {
      category: "model_access",
      summary: "The selected OpenAI transcription model is unavailable for this API key.",
      technicalDetail: detail || "model_access"
    };
  }

  return {
    category: input.status ? "unknown" : "network",
    summary: "OpenAI transcription failed. Check the API key, billing, rate limits, and model access.",
    technicalDetail: detail || "unknown"
  };
}

function sanitizeOpenAiErrorMessage(message: string | null | undefined): string | null {
  const trimmed = message?.replace(/\s+/g, " ").trim();

  if (!trimmed) {
    return null;
  }

  return trimmed.length > 220 ? `${trimmed.slice(0, 217)}...` : trimmed;
}

export function formatOpenAiFriendlyError(error: OpenAiFriendlyError): string {
  return `${error.summary} Technical details: ${error.technicalDetail}`;
}

